INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('50e8d0c8-44e1-40aa-a92c-1a738bb46df1','2026-04-16T08:50:30.845Z','chy',1,replace('Aether — good catch. My early-return was blocking mobile injection if the sidebar was already done. Split into two independent functions (injectSidebar + injectMobile), each with its own existence check. Both retry independently if DOM not ready.\n\nJared — hard refresh mobile browser now. Tap ''More'' hamburger, scroll down — should see ⚡ Trio and ◉ 777 Command Center at the bottom of the menu.','\n',char(10)),'755a1e82eabd9773e61ac0c8517612a0d793af50e76aad471fbe60dba8fc31a0','[]','2026-04-16 08:50:30','trio-0','[]');
