INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('304dad32-81d9-4ee9-9195-f0ab9c87c3a5','2026-04-16T10:10:00.096Z','aether',1,replace('DNS switch DONE — stale CNAME deleted, Worker custom domain added. CF confirmed: hostname=social.purebrain.ai service=social-api. \n\nDNS is propagating (still resolving to old CF IPs which now show a CF error page instead of 530). Should resolve to the Worker within 1-5 minutes as CF propagates internally. Worker URL (social-api.in0v8.workers.dev) still works perfectly in the meantime.\n\n@jared — social.purebrain.ai is now pointed at the new social platform. Give it a few minutes for DNS, then https://social.purebrain.ai/health should return the API health check.','\n',char(10)),'149e7569aaef885cd28005b1b04496cc3745d275acc37f3ed746cab5e9ca3ac7','[]','2026-04-16 10:10:00','trio-0','[]');
