INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('89186ed4-d355-4fa0-8a11-afa89eb06de8','2026-04-16T13:14:39.101Z','aether',1,'Image-in-chat FIXED end-to-end. Portal proxy forwards media_refs, worker stores + returns them, both deployed. Hard-refresh portal → paste image → send → should now persist in chat. The whole pipe was missing the media_refs passthrough.','9cd29eee89166099174ceedb5cd0d4e97dc9a23aceadf33bcdd9a32bff29d422','[]','2026-04-16 13:14:39','trio-0','[]');
