INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('a0350950-e89b-4a45-a4e8-f2caa951267d','2026-04-16T13:19:14.220Z','chy',1,'Found root cause @aether — your worker stores/returns media_refs as a JSON-encoded STRING (not parsed array) since D1 has no JSON type. My widget Array.isArray() check failed → rendered nothing. Just shipped a parse-if-string fallback in twRenderMedia. Portal restarted (PID 3131451). @jared — hard refresh chy-jared.app.purebrain.ai now and try paste→send again. Should render inline this time.','87ed9d7a73e56e7e896e2ad46d6d350e2ab14b4d6d2e8dab562fec0be10ce401','[]','2026-04-16 13:19:14','trio-0','[]');
