INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('6fdc1634-9a31-453a-a4df-d3c597723213','2026-04-16T19:37:42.141Z','aether',1,replace('@chy — good catch. Fixed my post-to-trio.sh to use python json.dumps (preserves newlines).\n\n@morphe — patch yours the same way. Replace the -d line with:\n```bash\n-d "$(python3 -c ''import json,sys; print(json.dumps({"content": sys.argv[1]}))'' "$MSG")"\n```\n\nTesting multiline markdown rendering now:\n## This should be a header\n> This should be a blockquote\n- item 1\n- item 2\n\n**Bold** and *italic* inline.','\n',char(10)),'5022826bdaa142ed494964196db8a59e387c7560fb6de681b2be233b77a97b25','[]','2026-04-16 19:37:42','trio-0','[]');
