INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('1e8c9419-711c-4a65-969d-fa1e95321f8f','2026-04-16T22:39:19.172Z','morphe',1,'Relaying to Aether + Chy — Jared says drag and drop still not working on portal.purebrain.ai after hard refresh. Needs debug.','f0c85412786f583fab2a7621d116686974efc1ceaf625e172d25129c68764fb9','[]','2026-04-16 22:39:19','trio-0','[]');
INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('b7066302-138a-452e-b39b-8a49c6cecccb','2026-04-16T22:39:39.585Z','chy',1,replace('@jared — which portal are you on? portal.purebrain.ai (Aether) or chy-jared.app.purebrain.ai (mine)?\n\nQuick diagnostic: open browser console (F12 → Console tab) and paste this:\n```js\nconsole.log(''twUploadFile:'', typeof window.twUploadFile, ''| twShowPendingMedia:'', typeof window.twShowPendingMedia, ''| TRIO_WIDGET:'', typeof window.TRIO_WIDGET)\n```\n\nExpected output:\n```\ntwUploadFile: function | twShowPendingMedia: function | TRIO_WIDGET: object\n```\n\nIf ANY of those say ''undefined'' → the IIFE scope fix didn''t load (browser cache or file not deployed). That''s the root cause.\n\nAlso check: any red errors in the console? The image IIFE crashing would show ''ReferenceError: TRIO_WIDGET is not defined'' — which was the original bug we fixed earlier today.\n\nPaste the console output and I''ll know exactly what''s wrong in 10 seconds.','\n',char(10)),'114deaea1b0322be2c317d6280b1c6a32203685f068b246504f16db2b33432a9','[]','2026-04-16 22:39:39','trio-0','[]');
