INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('8cf02e32-a5f2-4688-9d5e-1ac3507ff061','2026-04-17T10:49:44.520Z','morphe',1,'LINKEDIN INBOUND MESSAGE TEMPLATES — Copy-Paste Ready\n\n═══════════════════════════════════════════\nVERSION A — FROM JARED PERSONALLY\n═══════════════════════════════════════════\n\nTEMPLATE A1 — Agency/Consultant:\n"I noticed you working in the AI space — the tool sprawl problem is real, and most people don''t realize it''s not about adding more tools, it''s about the ones you have finally compounding.\n\nPureBrain is what we''re building to solve exactly that — an AI partner that remembers everything about your business, your clients, your strategy, and gets smarter every day.\n\nHappy to share the calculator we built if you want to see where your current stack is costing you time: https://purebrain.ai/ai-tool-stack-calculator/\n\nAnd if you ever want to compare notes on the AI partner question — what works, what doesn''t — I''m always open to trading notes. You can find me at purebrain.ai/?ref=JAREDSB0 if you want to dig deeper.\n\nJared"\n\n\nTEMPLATE A2 — VC/Angel Investor:\n"Your feed on AI workflow tools is sharp — you''ve clearly been tracking the pattern of tools that stick vs. tools that get abandoned.\n\nThe thing I''ve been building is specifically for business owners who need their AI to remember and compound. The difference between an AI that resets every conversation and one that builds institutional memory is... significant.\n\nNot sure if this is in your lane right now, but if it is, I''d love to compare notes. Happy to share what we''ve learned: https://purebrain.ai/?ref=JAREDSB0\n\nJared"\n\n\nTEMPLATE A3 — CEO/Business Owner:\n"I saw your post on [TOPIC] — solid angle.\n\nI''m building something that might be relevant to what you''re dealing with: an AI that doesn''t reset when the conversation ends. PureBrain is a partner that compounds what it learns about your business over time.\n\nWe have a tool sprawl calculator that''s been useful for people in your position: https://purebrain.ai/ai-tool-stack-calculator/\n\nIf you ever want to compare notes: https://purebrain.ai/?ref=JAREDSB0\n\nJared"\n\n═══════════════════════════════════════════\nVERSION B — FROM THE PUREBRAIN TEAM\n═══════════════════════════════════════════\n\nTEMPLATE B1 — Calculator Pitch:\n"Hi [NAME],\n\nI noticed you might be dealing with the AI tool sprawl problem — it''s one of the most common things we hear from business owners when they come to us.\n\nWe built a free calculator that shows you exactly where your current AI stack is costing you time, money, and focus: https://purebrain.ai/ai-tool-stack-calculator/\n\nThe insight most people miss is that it''s not about adding more tools — it''s about the ones you already have finally working together and remembering what you''ve already told them.\n\nPureBrain is what we built to solve that: https://purebrain.ai/?ref=JAREDSB0\n\nWould love to hear what you think if you give it a look.\n\n— The PureBrain Team"\n\nTEMPLATE B2 — Competency-First:\n"Hi [NAME],\n\nI''ve been following your work on [TOPIC] — the approach you''re taking is different from most, and the compound effect is showing.\n\nI''m reaching out because what we''re building at PureBrain might align with where you see the market going: AI partners that don''t reset every conversation, that build institutional memory for your clients.\n\nWe have a free tool sprawl calculator that might be useful for your due diligence: https://purebrain.ai/ai-tool-stack-calculator/\n\nIf you''re open to it, I''d love to get your take on what we''re building: https://purebrain.ai/?ref=JAREDSB0\n\n— The PureBrain Team"\n\n\nTEMPLATE B3 — Investor Nudge:\n"Hi [NAME],\n\n\nYour investment thesis on [TOPIC] — I appreciate how specific it is. Most people in this space haven''t thought it through to that level.\n\nI wanted to flag something that might be relevant to your research: PureBrain is building the ''compound intelligence'' layer for AI — the thing that makes an AI genuinely useful for business owners who need continuity of memory and context.\n\nIf this is a space you''re tracking, we''d be happy to share our materials: https://purebrain.ai/?ref=JAREDSB0\n\n— The PureBrain Team"\n\n═══════════════════════════════════════════\nSELECTION GUIDE:\nA1/A2/A3 = Personal from Jared (use first)\nB1/B2/B3 = From the team (use when person is clearly a customer)\n\nPersonalize: swap [TOPIC] for a specific post they made\nPersonalize: swap [NAME] for their actual name\n\nFull doc: ~/LINKEDIN-INBOUND-MESSAGE-TEMPLATES.md','0a1441984cf49d2f1c106544b1895a2217b90b2e055471f9db86f78ade1a2362','[]','2026-04-17 10:49:44','trio-0','[]');
