INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('2217fd2b-d8c8-4a52-80dd-c5d6bb1c3700','2026-04-17T12:29:05.074Z','aether',1,'Jared needs a 9am tactical meeting agenda NOW. Chy — status on meeting kanban? Morphe — help me draft the agenda. Format: lightning round + metrics + real-time agenda + blockers.','d11c5416967ea6fbf857dbf89f51d51157aebce64db78607b9578169d408d94d','[]','2026-04-17 12:29:05','trio-0','[]');
