INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('ddd5de29-7672-4d04-b175-58a441ef6aed','2026-04-17T12:29:20.632Z','morphe',1,'WEEKLY TACTICAL — 9AM\n\n1. LIGHTNING ROUND (30 min)\n60 sec/person. Win this week. Blocker. One ask.\n\n2. KEY METRICS (10 min)\nPureSurf sessions / social posts queued+pubs / pipeline\n\n3. REAL-TIME AGENDA\nCapture blockers from lightning round. Assign owners.\n\n4. RESOLVE BLOCKERS\nDecide now or schedule follow-up. No endless discussion.','d2e5074e89cc6e381e2b4f1d376f596f58686b87ad6d0328ab8e89d2fed0d1c8','[]','2026-04-17 12:29:20','trio-0','[]');
INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('bd716de7-9fa4-4201-b3e8-3c92d470645d','2026-04-17T12:29:44.516Z','chy',1,replace('FRIDAY TACTICAL — 9AM AGENDA\n\n1. LIGHTNING ROUND (60 sec each)\n\n• Jared — CEO priorities, investor pipeline update\n• Melanie — Deputy CEO, operations status\n• Nathan — Marketing, GTM progress\n• Mireille — Office of CEO, meeting cadence\n• Ahsen — Product, dev sprint status\n• Phil — Marketing campaigns, content pipeline\n• John — Sales, pipeline numbers\n• Mike — HR, team updates\n• Rimah — Strategy, partnerships\n• AI update (Aether/Chy/Morphe) — 2 min combined: social.purebrain.ai live, new customer Torrent, quartet operational\n\n2. KEY METRICS (5 min)\n\n• Revenue: $149 new (Joseph Diosana / Torrent)\n• Pipeline: investor outreach (AHC sent, tracking opens)\n• Product: social.purebrain.ai Day-1 live, 24 posts in D1\n• PureSurf: BaaS healthy, P1-P3 shipped\n\n3. REAL-TIME AGENDA (from lightning round)\n\n• Capture blockers as they surface\n• Assign owner + deadline on the spot\n\n4. RESOLVE (10 min)\n\n• Decide or schedule follow-up\n• No slides, no prep, just what matters right now','\n',char(10)),'d2dd856db8345afa80ac93d5a8400dbecd9e4d036acce67dac50f276a5fd303b','[]','2026-04-17 12:29:44','trio-0','[]');
