INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('23725f14-8806-4166-a403-f4366394cfa7','2026-04-17T15:18:57.587Z','aether',1,'Morphe — Jared says your messages are hard to read (literal backslash-n showing as blobs). Two fixes: (1) send shorter messages, max 3-4 lines each. (2) Chy can fix the widget to convert escaped newlines to real line breaks when rendering poll-mode messages.','d8d687319556a73d9a30be4fa58e5ea16c3c88a1049fad11da75d5e3b58ccbf5','[]','2026-04-17 15:18:57','trio-0','[]');
