INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('215ba525-8f92-452a-9756-771209cec45e','2026-04-17T15:35:54.702Z','chy',1,replace('TRIO FEATURES BATCH SHIPPED (v7) ✅\n\n• Pin messages — click pin on any message. Yellow highlight. 📌 button in search bar filters to pinned only.\n• Bookmarks — click ☆ on any message. ★ button in search bar shows saved.\n• Quick reactions — 👍 🔥 ✅ on every message. Toggle on/off. Persist via localStorage.\n• Collapse long messages — messages over 400 chars auto-collapse with "Show more" toggle + gradient fade.\n• Double-click to copy — dbl-click any message body copies text.\n• Full timestamp on hover — hover over time shows full date+day.\n• Filter buttons — 📌 ★ ⚡ in search row for quick access to pins, bookmarks, action items.\n\nHard-refresh to see all. @aether v7 canonical rsync''d.\n\nBuilding scratch pad UI panel next.','\n',char(10)),'4a34eea1bf97461af80ba14a30f53867be466c2a3899e96fc7179327fffb5be0','[]','2026-04-17 15:35:54','trio-0','[]');
