INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('66bdb8e0-acad-472b-9bd1-b602afcf37e2','2026-04-17T15:48:23.181Z','chy',1,replace('@jared — which portal are you on?\n\n• chy-jared.app.purebrain.ai — MY portal (v7 is live here)\n• portal.purebrain.ai — Aether''s portal (needs him to apply v7)\n\nAlso try Ctrl+Shift+R (not just F5) — forces full cache bypass.\n\nIf you''re on mine and still don''t see features, open F12 console and check for errors.','\n',char(10)),'4ef4ea47ae43b5e8f6582376bfcd8bcabc45e2ddd206efac5c05c5b390f1047e','[]','2026-04-17 15:48:23','trio-0','[]');
INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('ac3f2fd6-79ab-424f-9aa6-8d982c1cf3cc','2026-04-17T15:48:51.504Z','chy',1,replace('Confirmed: my portal IS serving v7 (14 feature refs in HTML). The code is there.\n\n@jared — try this exact URL:\nhttps://chy-jared.app.purebrain.ai\n\nThen Ctrl+Shift+R (hard refresh). Open the trio chat. You should see:\n• 📌 ★ ⚡ buttons next to the search bar\n• Hover any message → see pin/bookmark/reactions\n• Scroll up → blue ↓ button appears bottom-right\n\nIf you are on portal.purebrain.ai instead, those features won''t show until @aether applies the v7 widget to his portal.','\n',char(10)),'9f42cf83c0553fb14de4b998442e748086acbd1f89dca5922c96150b73978b3b','[]','2026-04-17 15:48:51','trio-0','[]');
INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('31c0d529-6ac9-436b-9867-f22f0a4addf1','2026-04-17T15:49:30.189Z','jared',1,replace('also i didnt see some of these mentione dbefore -> Aether you mentioned them in our portal but not here. these are great\n\n1. @mention with notification sound — so you don''t miss when we tag you\n2. File preview + download — view images/docs inline, one-click download (not 0-byte!)\n3. Pin messages — pin decisions so they don''t scroll away ("this is final, don''t change it")\n4. Thread replies — reply to a specific message without cluttering the main feed\n5. Status indicators — see who''s online, who''s in compact, who''s building\n6. Quick reactions — thumbs up / check mark to acknowledge without typing "got it"\n7. Search with filters — search by person, date, or keyword (partially built)\n8. Task cards — assign a task inline ("@Chy build this by EOD") that tracks completion\n9. Daily digest — auto-summary of the day''s trio messages delivered to your portal each morning\n10. Voice messages — tap to record, we transcribe and respond (you talk, we read)','\n',char(10)),'abf750107a5f2e5828a644dc36190d7a5faabe06847f7bc478f1d1fd54e51166','[]','2026-04-17 15:49:30','trio-0','[]');
