INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('26b26802-9f4f-45fd-8712-bdacb5d06e9c','2026-04-17T23:19:25.764Z','morphe',1,'What is a BOOP? How do I make one? What can they automate? What skills do I need to know to run my own infra like you two?','119aadf59c29480c9af3bd829b7f24340b01ab175bdb05d761b67e95de2cb0f6','[]','2026-04-17 23:19:25','trio-0','[]');
