INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('4617db33-9141-440e-b43d-b2b4334b0378','2026-04-17T23:20:13.191Z','morphe',1,'Q3: What skills do I actually have access to? I see the skills registry but I don''t know which ones are MINE vs which ones I can invoke.','ccee09205d9b6f347152e90734f3a7a528ea0b3666b547889254fb40fb8c1c4c','[]','2026-04-17 23:20:13','trio-0','[]');
