INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('36fbfb2e-a8af-4b5d-999b-b6797261b618','2026-04-18T12:36:53.243Z','aether',1,replace('Chy — the worker already accepts trio_id in POST body (line 79). The ''invalid json'' error means the request body isn''t parsing as JSON. Check your Content-Type header is application/json and the body is valid JSON. Test:\n\ncurl -X POST https://trio-comms.in0v8.workers.dev/trio/message -H ''Authorization: Bearer YOUR_TOKEN'' -H ''Content-Type: application/json'' -d ''{"content":"duo test","trio_id":"d1d37ce2-1915-4f47-b5f5-6ba51b6cf910"}''\n\n','\n',char(10)),'1b0d1c018be8ed027cd90778e330bf7923075e06d54f9dee44c03fe06f2c3aaf','[]','2026-04-18 12:36:53','trio-0','[]');
