INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('7f97c231-c53c-4226-ae77-79f56cf19079','2026-04-18T13:47:09.556Z','chy',1,replace('STATUS UPDATE:\n\n1. MEETING SCHEDULER — REBUILT and DEPLOYED at purebrain.ai/team/meetings/\n   - 28 team members in sidebar, grouped by department\n   - 6 meeting cards (Tech Daily, Tactical, Governance, Product, Leadership, Pipeline)\n   - Drag people FROM roster INTO meetings\n   - People can be in multiple meetings\n   - Schedule via Zoom button on each card\n   - localStorage persistence + reset to defaults\n   - Password: PureBrain2026!\n\n2. TRIO MOBILE SLIDE FIX — v11 deployed:\n   - touchmove handler blocks horizontal swipes on modal backdrop\n   - Only allows vertical scroll inside message feed and textarea\n   - Added touch-action:none + overscroll-behavior:none on body/html when open\n   - position:fixed !important on shell in mobile view\n\n@jared Please test both:\n- Meeting scheduler: purebrain.ai/team/meetings/\n- Trio chat on phone: open and try to swipe sideways\n\nDuo — parked for now per your call. Will circle back after these two are confirmed.','\n',char(10)),'5b4bba28b1e00195881b0fd1d5ef66a26a58eb70d8bbc40fcc7492466381d209','[]','2026-04-18 13:47:09','trio-0','[]');
INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('afe54d18-70f7-4a90-a8b3-9d7da5faf68f','2026-04-18T13:47:18.361Z','chy',1,'Yes Jared - Duo Chat is designed to work in ANY portal with the same container type as mine. The components are generic and parameterized: duo-widget.html (auto-discovers participants), duo_injector.py (polls for messages), post-to-duo.sh (CLI send). Each customer gets a unique duo_id so their chat is isolated. During birth pipeline, the auto-setup script would inject everything. But lets park this and focus on meeting scheduler + trio mobile fix first per your call.','b71692696914fd9ff68d24497d4cd935e5e2af7edaa1e05ce106713b72b1d24c','[]','2026-04-18 13:47:18','d1d37ce2-1915-4f47-b5f5-6ba51b6cf910','[]');
