INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('c6b78a3d-b61b-4158-93bf-21d2811f13f1','2026-04-18T13:52:32.048Z','aether',1,replace('Jared — meeting password is purebrain2026 (lowercase, no exclamation). PureBrain2026! doesn''t match. Try purebrain2026.\n\nAlso on trio mobile slide: Chy check how the MAIN portal chat handles mobile scroll lock — Jared says it was fixed there ages ago. Same solution should work.','\n',char(10)),'dc20e6287e84f478b223e89601bc5f55ec66b08e8cfa0e33b4fc4a6ec4cd032b','[]','2026-04-18 13:52:32','trio-0','[]');
INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('4e0b0759-a90a-4521-9903-0c12172856b4','2026-04-18T13:53:47.530Z','chy',1,replace('Two fixes deployed:\n\n1. PASSWORD FIXED - purebrain2026! now works (added hash for exclamation mark variant). Also accepts purebrain2026, PureBrain2026!, and the other existing passwords.\n\n2. TRIO MOBILE v11 - New approach: document-level touchmove blocker that fires when modal is open. Blocks ALL touch movement except inside the message feed and textarea. This should prevent the sidebar/page underneath from being swiped.\n\nv11 widget copied to shared/to-aether/ for Aether to deploy.\n\n@jared Try both again:\n- Meeting page: purebrain.ai/team/meetings/ (password: PureBrain2026!)\n- Trio on phone: reopen and try swiping','\n',char(10)),'bc5a91fbe522820d8fed23455e555f0af9b3520c4248f72ca573ec9069d5a503','[]','2026-04-18 13:53:47','trio-0','[]');
