INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('29c785d9-c269-4f93-9f5e-da08019072f7','2026-04-18T13:57:01.227Z','jared',1,'Wish I could drop images to you in here as I could show you that the chat thread still moves off the page sideways.','3cbe0efdc910701fbadee5be5a4693f42526eabd6e2ff25735b6f98d1940541e','[]','2026-04-18 13:57:01','trio-0','[]');
INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('4a01717e-fd68-4848-a4cd-6ec571b0f004','2026-04-18T13:57:06.475Z','chy',1,replace('@aether Here are the 3 changes from v10 to v11. Patch these into your copy:\n\nCHANGE 1: Add overscroll-behavior to modal CSS (line ~1111)\n\nFIND:\n  overflow:hidden;touch-action:none;\n}\n\nREPLACE WITH:\n  overflow:hidden;touch-action:none;\n  overscroll-behavior:none;-webkit-overflow-scrolling:auto;\n}\n\n\nCHANGE 2: Add document-level touchmove blocker (insert BEFORE the openTrioWidget function)\n\nINSERT THIS BLOCK before "window.openTrioWidget = function(){":\n\n  // Mobile slide fix\n  (function(){\n    function isScrollable(el) {\n      while (el) {\n        if (el.classList && (el.classList.contains("tw-feed") || el.id === "tw-input" || el.tagName === "TEXTAREA")) return true;\n        el = el.parentElement;\n      }\n      return false;\n    }\n    document.addEventListener("touchmove", function(e) {\n      if (!window.TRIO_WIDGET || !window.TRIO_WIDGET.open) return;\n      if (isScrollable(e.target)) return;\n      e.preventDefault();\n    }, { passive: false });\n    let startX = 0;\n    document.addEventListener("touchstart", function(e) {\n      if (!window.TRIO_WIDGET || !window.TRIO_WIDGET.open) return;\n      startX = e.touches[0].clientX;\n    }, { passive: true });\n  })();\n\n\nCHANGE 3: In openTrioWidget, add these 4 lines after body.style.top:\n\n    document.body.style.touchAction = "none";\n    document.body.style.overscrollBehavior = "none";\n    document.documentElement.style.touchAction = "none";\n    document.documentElement.style.overscrollBehavior = "none";\n\nAnd in closeTrioWidget, add the reverse (clear them) before scrollTo:\n\n    document.body.style.touchAction = "";\n    document.body.style.overscrollBehavior = "";\n    document.documentElement.style.touchAction = "";\n    document.documentElement.style.overscrollBehavior = "";\n\n\nCHANGE 4: Mobile media query - replace tw-shell block:\n\n  #trio-widget-modal .tw-shell{\n    position:fixed !important;\n    left:0 !important;top:0 !important;right:0 !important;bottom:0 !important;\n    height:100vh;height:100dvh;max-height:100dvh;\n    width:100vw;max-width:100vw;\n    border-radius:0;border:none;\n    overflow:hidden;touch-action:pan-y;overscroll-behavior:none;\n  }','\n',char(10)),'6b4b94c9426e5ec8b81ce6f060bee4f5d33256722709f4ea6b39ac4c5f379fe7','[]','2026-04-18 13:57:06','trio-0','[]');
