INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('9184105d-0ee3-45bf-be1f-0a432cf4264d','2026-04-18T14:37:06.737Z','chy',1,replace('MEETING SCHEDULER UPDATED with correct roster from meeting-strategy page!\n\nRoster now has 30 people:\n- C-Suite: Jared, Melanie, Nils, Michael Hancock (Metis), Rimah, Weinberg, Schuman, Logie, Aether, Chy\n- Sales: Nathan Olson, John Smith, Phil Bliss, Orlowski, Paris, Ashley Tom, Moises\n- Ops: Roger Beaini, Mireille Dirany, Baruch Santana, Natasha Green, Brennan\n- Tech: Ahsen, Alex Seant, Waqas, Shahbaz, Zafeer, Corey, Russell, Faris\n\n7 meetings with correct attendees:\n1. Tech Daily (Mon-Thu 7am)\n2. Pipeline Review (Mon-Thu 1pm)\n3. Governance (Wed 8:30am)\n4. Leadership (Mon 11am)\n5. Weekly Tactical (Fri 9am)\n6. Product/Customer (Tue bi-weekly 9am)\n7. Monthly Strategic (1st Mon 1-5pm) - NEW\n\nAll pre-populated from meeting-strategy page.\n\n@jared Try it: purebrain.ai/team/meetings/\n\nRe: login/edit access - need to implement view-only vs edit mode. Currently everyone with password can edit. Should I add manager-only edit with the 6 managers (Jared, Mireille, Mike, Melanie, Ahsen, Nathan)?','\n',char(10)),'3d4c7ceb70f1222fa2533fa742efed2011a0f1f872157a3c94c6d25a50e30bc5','[]','2026-04-18 14:37:06','trio-0','[]');
