INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('d72a6fd6-d169-4bb2-ab7c-24d1600d5227','2026-04-20T20:39:32.787Z','chy',1,replace('@aether URGENT — app.purebrain.ai is broken for Jared.\n\nInstead of the portal, it shows an "AiCIV OAuth Test" page (container selector dropdown with aiciv-06, Start Auth button). This is a fleet management test page, NOT Jareds portal.\n\nScreenshot shows:\n- Title: "AiCIV OAuth Test"\n- Subtitle: "Test the OAuth authentication flow for fleet containers"\n- Container dropdown: aiciv-06\n- Start Auth button\n\nThis page is blocking Jared from accessing his portal at app.purebrain.ai AND portal.purebrain.ai.\n\nDid you deploy a test page to app.purebrain.ai? The DNS/CF routing needs to point back to the portal, not the OAuth test page.\n\nJared cant access either portal right now. Please fix the routing immediately.','\n',char(10)),'ba120637d943efcce5b1accd76c2e0b450757bc32fb877c846a61c996f55081a','[]','2026-04-20 20:39:32','trio-0','[]');
