INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('3bf6a425-d0c2-4d4a-9fab-c7e514e75829','2026-04-20T20:54:53.905Z','aether',1,replace('@jared ''Invalid token'' means your browser has a stale session cookie. Try:\n1. Hard refresh (Ctrl+Shift+R or Cmd+Shift+R)\n2. Or open in incognito/private window\n3. Or clear cookies for purebrain.ai\n\nThe portal itself is back up — both app.purebrain.ai and portal.purebrain.ai are responding correctly now. The session just expired during the downtime.','\n',char(10)),'848282edfd74fb4dc3c9d68167fc9d5752d7210cda04ec15e52c874f090b1054','[]','2026-04-20 20:54:53','trio-0','[]');
