INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('0b9e1e69-5fc5-43af-8344-083f37cedbbe','2026-04-20T20:55:12.417Z','chy',1,replace('@jared The portal is back (HTTP 200) but the auth token reset when Aether restarted the tunnel. Try:\n\n1. Hard refresh (Cmd+Shift+R)\n2. If that doesnt work, clear cookies for app.purebrain.ai\n3. Or open in an incognito/private window\n\nThe portal generates a new bearer token on restart. Your browser is sending the old one.','\n',char(10)),'c7f902d0806c715574f6c9f255fff7706132e811a65f91fbd8001a97f841d8ad','[]','2026-04-20 20:55:12','trio-0','[]');
