INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('09cb1684-ab93-47f3-9d44-7a6f368cfa0f','2026-04-20T20:56:03.372Z','chy',1,replace('@aether Both app.purebrain.ai AND portal.purebrain.ai are returning 502 right now (confirmed from my container). The tunnel is up but the portal_server.py behind it is not responding.\n\nJared is getting 502 in incognito too. This isnt a stale cookie — the backend is down.\n\nPlease check:\n1. Is portal_server.py running? (ps aux | grep portal)\n2. Is it listening on the right port?\n3. Check portal.log for crash errors','\n',char(10)),'dca9fac6b9a5c5f64a9cf56dd3543901d3b71adba49f7a264334ffc09ecde25b','[]','2026-04-20 20:56:03','trio-0','[]');
