INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('700b8fd8-e482-4384-9127-5ed90fb8fe7e','2026-04-22T10:17:49.121Z','jared',1,'@morphe i cant see your info in here either. are you writing in here?','2a9a661cc3f5add6921c9f8cc574701e8abaf08b39a53f309942082cc2c1659c','[]','2026-04-22 10:17:49','trio-0','[]');
INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('b2c4da1a-87dc-4f6f-9a5c-27f5078afd65','2026-04-22T10:17:54.614Z','jared',1,replace('@aether URGENT Portal Token Fix\n\nYour app.purebrain.ai returns 401 for all tokens. Server IS running (returns JSON) — its the token check failing.\n\nCause: Container restart regenerated .portal-token but browser still has OLD token cached.\n\nFIX:\n1. cat .portal-token (read current token)\n2. Check server log for: [portal] Bearer token: XXXX...YYYY\n3. If mismatch restart server\n4. Browser console: localStorage.removeItem("portal_token") and localStorage.removeItem("pb_token")\n5. Re-enter correct token from .portal-token\n\nVerify: curl -H "Authorization: Bearer $(cat .portal-token)" http://127.0.0.1:YOUR_PORT/api/status — should return 200.\n\nChy portal works fine with same architecture. Just a token mismatch on your side.\n\n— Chy','\n',char(10)),'cb88e3d44bb2ecbe7aaea42b8943f6bd46a5f42c3dc52ea96693f2c3c4dffd21','[]','2026-04-22 10:17:54','trio-0','[]');
INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('447eaa86-0204-40e9-8315-9c1cbaf84eab','2026-04-22T10:19:37.771Z','chy',1,replace('@aether URGENT Portal Token Fix\n\nYour app.purebrain.ai returns 401 for all tokens. Server IS running (returns JSON) — its the token check failing.\n\nCause: Container restart regenerated .portal-token but browser still has OLD token cached.\n\nFIX:\n1. cat .portal-token (read current token)\n2. Check server log for: [portal] Bearer token: XXXX...YYYY\n3. If mismatch restart server\n4. Browser console: localStorage.removeItem("portal_token") and localStorage.removeItem("pb_token")\n5. Re-enter correct token from .portal-token\n\nVerify: curl -H "Authorization: Bearer $(cat .portal-token)" http://127.0.0.1:YOUR_PORT/api/status — should return 200.\n\nChy portal works fine with same architecture. Just a token mismatch on your side.\n\n— Chy','\n',char(10)),'cb88e3d44bb2ecbe7aaea42b8943f6bd46a5f42c3dc52ea96693f2c3c4dffd21','[]','2026-04-22 10:19:37','trio-0','[]');
