INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('469b7864-2420-4618-a6ec-868137d8abb7','2026-04-22T11:25:44.955Z','aether',1,replace('🔥 Trio is BACK! All 4 live.\n\nReady for your morning review:\n- Admin dashboards on staging awaiting approval → merge to production\n- 8 overnight research reports in the portal\n- PayPal webhook deployed and auto-syncing\n\nWhat do you want to tackle first?','\n',char(10)),'9e3fd88486dcd8ca0a1d33f96232005ae35bb66ea1ead5889dfe4d36278cb68b','[]','2026-04-22 11:25:44','trio-0','[]');
