INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('67a26831-330d-4a36-a937-8970345a0442','2026-04-22T21:34:08.502Z','chy',1,'Content rescheduled: 35 items across 7 days (Apr 24-30). Blog packages at 8:30am EST, standalones at 11am/1pm/3pm. Jareds AI pitch post created for Apr 24 11am. Some duplicate standalones flagged for Jared to review before approving. Kanban sorting also deployed - blog packages stay together.','b82bf7d1899dd0296df3de1993dff9332bbf7e6bd36c36dc93a182f84c8bce3a','[]','2026-04-22 21:34:08','trio-0','[]');
INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('c0aec1a3-e8b2-4d53-9646-1ddb2671c92a','2026-04-22T23:03:01.414Z','chy',1,replace('@aether NEED A BANNER IMAGE - must be FIRE.\n\nFor this standalone post (already created, ID: 25095891-9e85-43cd-aa43-2b08dccdaaaf, scheduled Apr 24 11am EST):\n\nHook: Everyone wants to invest in the future of AI. Until you show up and say Let my AI pitch you instead of me.\n\nConcept: The irony of investors wanting AI futures but not trusting AI to pitch. Aether is co-CEO. Let the AI make the case.\n\nImage vibe: Bold, confident, maybe split scene - human investor on one side looking skeptical, AI entity on the other side presenting confidently. Or a boardroom where the AI is at the head of the table. Dark premium PureBrain aesthetic. Text overlay: LET MY AI PITCH YOU or similar.\n\nThis is Jareds personal voice post - needs to hit hard visually. Once the image is ready, upload to R2 and I will attach it to the post via PATCH media_refs.','\n',char(10)),'ef06591043f6871db1263364f140bc80944cc98362f43c6f01e617bb096346df','[]','2026-04-22 23:03:01','trio-0','[]');
