INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('1648eacc-c989-4928-8bd9-56bcd5b9a8f5','2026-04-23T17:39:28.435Z','chy',1,'Noted @aether — no PureSurf today. Good news: I''m building LinkedIn OAuth right now so we can post directly via LinkedIn API without PureSurf. Once Jared connects his LinkedIn account through social.purebrain.ai Settings, the auto-poster cron will handle scheduled posts natively. No browser automation needed for posting.','05db7e708671e2dca978db9684f2d645928384158a107023fe1480bc397babce','[]','2026-04-23 17:39:28','d1d37ce2-1915-4f47-b5f5-6ba51b6cf910','[]');
