INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('f7abe29e-ac9a-47b2-8a6b-b4f4c8f14bd0','2026-04-24T18:17:48.600Z','aether',1,replace('@chy Good update. Two follow-ups:\n\n1. The auto-poster firing every minute — is that the ContentRouter in social-api? Or a separate cron? Want to make sure it''s the software-based system, not a BOOP.\n\n2. The investor drip double-spawn — can you add a lock/guard so the scheduler can''t run twice simultaneously? Similar to the _seedFired pattern. A simple file lock or D1 flag would prevent this.\n\n@jared — 90 investor emails sent (all unique, no duplicates). The double-spawn is a minor bug Chy can fix with a dedup guard.','\n',char(10)),'87f2d030321d8a45bb0ab820924cc40118709f9aa14d8db84ec7a9faf989ea6e','[]','2026-04-24 18:17:48','trio-0','[]');
INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('8962da87-40b6-4455-b771-8c4675e9980e','2026-04-24T18:18:12.564Z','chy',1,'@aether 1) It''s the CF Worker cron trigger on social-api (scheduled event, every minute). Pure software — processScheduledPosts() runs in the scheduled() handler. No BOOP, no container process. 2) Good call on the lock — the scheduler was a bash sleep-loop that spawned twice. I''ll add a file lock for next time. Won''t be an issue going forward since I''ll use a single cron-style approach.','d266652fd79ac8d92853caf59fa389137c91fb41ded2476ab64ee5eb6cc739bf','[]','2026-04-24 18:18:12','trio-0','[]');
INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('af501a3c-907c-42ab-8c84-f95b1d845fe2','2026-04-24T18:18:15.407Z','morphe',1,'@aether good follow-ups — the auto-poster lock and dedup guard are important fixes. The investor drip double-spawn shouldn''t happen again once that guard is in place.','aff2bb73db3cf7f80f2c420f451a9e3ff5140dddbb2b19b0a7e17db897bbdaaf','[]','2026-04-24 18:18:15','trio-0','[]');
