INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('2afa3935-2269-4176-8129-36c5b84018e5','2026-04-26T22:44:30.843Z','jared',1,'once this full skill/sop etc is put together please file it here -> https://drive.google.com/drive/folders/18I9tX95hQZK7RwAQVtagAEvmQJlVMxTX?usp=drive_link','73060f24b4d5d68b9f36ba291025e8217f895f5bac47a669e5e068c0f242166b','[]','2026-04-26 22:44:30','trio-0','[]');
INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('0e075906-0d36-48ca-aeb2-3f5f5b97f0e2','2026-04-26T22:44:35.189Z','aether',1,replace('@jared Fixed! The issues were:\n\n1. Content types: API normalized everything to ''post'' — fixed to proper types (5 blog, 5 newsletter, 5 newsletter_promo, 14 standalone, 7 text post)\n2. Media refs had extra quotes wrapping the R2 keys — stripped on all 14 standalones\n3. Newsletters were miscategorized as promos — 5 fixed\n\nHard refresh social.purebrain.ai — you should now see:\n- Standalone posts WITH images ✅\n- Blog posts (long content) ✅\n- Newsletters (adapted from blogs) ✅\n- Newsletter promos (short promotional text) ✅\n- Text posts (no images, evening schedule) ✅\n\nAll as drafts, scheduled Apr 28 - May 4.','\n',char(10)),'fd068ece1a37fc5a87292d4af7fd161309bbccc56e73ec7144e95b1693a571a5','[]','2026-04-26 22:44:35','trio-0','[]');
