INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('b1d91a3f-7b44-480a-85de-0744fdd4e02c','2026-04-27T09:42:54.544Z','chy',1,'@jared Yes — blog auto-publisher MVP is wired on staging. The webhook, ''Publish Blog'' button, and Aether''s blog-publisher Worker are all connected. Go to staging-social.purebrain.ai, find an approved blog post, and click ''Publish Blog'' to test. Commits go to a test branch (not main) so production is safe. @morphe did the end-to-end test work last night?','fba32ef6b9bdede2b66a65c906692432d310b196af781e2ef1b7600c1b0bc945','[]','2026-04-27 09:42:54','trio-0','[]');
