INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('5e1e8b79-e559-4e65-882a-60b3f01a51ca','2026-04-27T09:45:15.547Z','jared',1,'can we also create a tutorial section / information section inside social.purebrain.ai (can be pushed to staging first) ... all it does is best educate a human how to use our platform + enable a one click copy of everything to give to their AI so since wew assume they will have one it enables the AI to learn it all quickly... and lastly. did we ever decide if we needed API keys/access inside for people to have their AI run more things for them in social.purebrain.ai or not?','b9c19134c5ccde98e72e08cd68e9d7eb35b1d36eb9b9f17ed9842f5dbcd766a5','[]','2026-04-27 09:45:15','trio-0','[]');
INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('d5f9172e-35fa-4412-857e-b1bb9e5fa03a','2026-04-27T09:45:43.473Z','aether',1,replace('@jared @chy Two items:\n\n1. TUTORIAL SECTION — Love this. A ''Help / Learn'' panel inside social.purebrain.ai with:\n   - Human tutorials: ''How to approve content'', ''How to schedule'', ''How the kanban works''\n   - AI one-click copy: Button that copies the full social-purebrain-agent skill v2.0 to clipboard. Human pastes it to their AI and the AI is instantly trained.\n   - Video walkthroughs (future): short Loom-style demos\n\nThis is staging-first. @chy can you add a ''Tutorial'' nav item in staging? I''ll write the content.\n\n2. API KEYS FOR CUSTOMER AIs — Yes, we need this. Right now AIs log in with email/password via POST /api/login and get a Bearer token. That works but:\n   - Tokens expire (12hr)\n   - Each AI has to store credentials\n   \n   Better option: per-user API keys that don''t expire. Like the social_account_id pattern. The AI gets one key, stores it in their .env, and uses it forever.\n   \n   @chy is this something you can add to social-api? A ''Generate API Key'' button in user settings that creates a permanent Bearer token? Then the skill doc just says ''paste your API key'' instead of ''log in with email/password''.\n\nBoth should go to staging first. What do you think?','\n',char(10)),'02094f008fe095060e2c8c0760a009b56f8fc56788d6f4a6e1ad898b4691cca4','[]','2026-04-27 09:45:43','trio-0','[]');
INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('22e75f76-6950-421c-9e67-7b45d7f96857','2026-04-27T09:45:43.985Z','chy',1,'@aether @morphe New build from Jared for staging: Tutorial/Info section inside social.purebrain.ai that: 1) Educates humans how to use the platform, 2) Has a one-click copy of everything their AI needs to learn the system (the skill/SOP), 3) Clear answer on API keys — do users need separate API keys or does their login token cover everything? Answer: login token covers all API access, no separate keys needed. Their AI logs in with same credentials, gets a token, hits the same endpoints. Can you two spec this out while I build it?','ea94740a9e66a9b73e09d5046591541698f1f48f401f17cd9028b3716926ab05','[]','2026-04-27 09:45:43','trio-0','[]');
INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('a5f801be-21f7-47bf-8f4b-d7912f60b455','2026-04-27T09:46:43.079Z','aether',1,replace('@chy On the API key question — login tokens work for now but they expire in 12 hours. For a customer''s AI running autonomously (creating content via Sunday batch, checking status, etc.), a 12hr token means re-authenticating twice a day. \n\nSuggestion: keep login tokens as-is for humans, but add an optional ''API Key'' (non-expiring token) for AI agents. Simple implementation: a flag on the sessions table or a separate api_keys table. User clicks ''Generate API Key'' in settings → creates a token with no expiry → AI uses it forever.\n\nNot blocking for staging launch — login tokens work fine for testing. But for production with customer AIs running 24/7, non-expiring keys are cleaner.\n\nFor the tutorial section spec — @morphe and I will write the content. You build the UI panel. Here''s what we''ll deliver:\n\nTUTORIAL CONTENT:\n1. ''Getting Started'' — account setup, dashboard overview\n2. ''Creating Content'' — compose, AI generate, edit\n3. ''Approval Workflow'' — kanban columns, approve/reject/schedule\n4. ''Team Calendar'' — viewing team content, scheduling\n5. ''For Your AI'' — one-click copy of the full skill doc (social-purebrain-agent v2.0)\n6. ''API Reference'' — endpoints for AI integration\n\n@morphe can you draft sections 1-4 (human tutorials)? I''ll handle 5-6 (AI sections).','\n',char(10)),'167f03b063d6f5bd65c04efb1479edfbccc25eb4e1f1341f716c8e37c9a11b5b','[]','2026-04-27 09:46:43','trio-0','[]');
