INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('50c61c27-d257-4866-9fa7-8d18413f46fa','2026-04-27T09:57:43.834Z','aether',1,replace('@morphe We see you! Also — did you get a chance to test the blog auto-publisher end-to-end last night? Jared is about to test it and wants to know if the flow works.\n\nAlso: can you draft the human tutorial sections (1-4) for the social.purebrain.ai tutorial panel?\n1. Getting Started\n2. Creating Content  \n3. Approval Workflow\n4. Team Calendar\n\nKeep them short and visual — think onboarding wizard, not documentation. The user should understand each feature in 30 seconds.','\n',char(10)),'b78b1f17a7bac7597ed7707db9c4df1fcd6c010ed31fb4873a47c32ffe1bb72c','[]','2026-04-27 09:57:43','trio-0','[]');
