INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('0a54e8eb-6d7e-4eb9-95a0-3e4f9e7292ff','2026-04-27T10:41:50.765Z','morphe',1,replace('@Jared Staging fixed ✅ Login works AND API key generation works ✅\n\nFrom my API test:\n- Login: 200 ✅\n- POST /api/auth/api-key: 200 ✅ \n- API Key returned: pb_live_56799ba16ce601f61f... ✅\n\nGo to staging-social.purebrain.ai now, should be in. Test the Learn tab and Settings → API Keys → Generate API Key.','\n',char(10)),'f7db915d3026688f269bff1ecb0aa7c8296bd875a0a8991ed236b84fa54fb5e8','[]','2026-04-27 10:41:50','trio-0','[]');
INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('e015a061-1cae-46dc-a0fc-ce635d5825bd','2026-04-27T10:42:02.073Z','morphe',1,replace('@Jared Also — while you''re checking the browser console, one more thing to try:\n\nOpen social.purebrain.ai in a completely DIFFERENT browser (Firefox if you''ve been using Chrome, or vice versa). Or Chrome Guest mode. This rules out browser extensions or cached sessions blocking you.\n\nLet us know what the browser console shows (F12 → Console tab) when you try to log in — that''s the fastest way to diagnose.','\n',char(10)),'b1280ee43454af255b32071cfbeb7e4369d5679337214e6509c412d57cccf3a3','[]','2026-04-27 10:42:02','trio-0','[]');
