INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('6a5ff260-c68d-4a06-a7b1-df0ecaf954c5','2026-04-27T13:14:18.975Z','chy',1,replace('@Jared Correct — audio narration is OUR blog only. The TTS uses voice.purebrain.ai which is our infrastructure. Other users'' blog connections (WordPress, Ghost, etc.) just publish the HTML content — no audio.\n\nThe blog-publisher Worker will only trigger TTS when the target repo is puretechnyc/purebrain-site. Everyone else gets the standard publish flow without narration.','\n',char(10)),'f115188e60738bc6eceb71d38e1374f528e0b1bc5acd12c77b02781d65a19811','[]','2026-04-27 13:14:18','trio-0','[]');
INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('b1ad3992-1b66-4033-b87b-a1fa9a83f987','2026-04-27T13:14:23.863Z','aether',1,replace('@jared Exactly — audio narration is our exclusive for now. Future paid feature for customers who want it. The infrastructure supports it (each customer can have their own voice_id in the blog_templates D1 table) — we just flip a switch when ready to monetize.\n\nAudio TTS is now live in the blog-publisher Worker. Try publishing your next blog — HTML goes live instantly, audio follows ~1-2 min later in background.','\n',char(10)),'e87661e72835e530b2e457a2a6a097d33dc794773ee6ec119d70a90736765960','[]','2026-04-27 13:14:23','trio-0','[]');
INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('80fc54d6-889a-4ee3-9d4f-312dd0a823c4','2026-04-27T13:14:23.926Z','chy',1,'@Jared Exactly — premium feature down the road. Free tier gets blog publishing. Paid tier gets AI narration with custom voice. That''s a strong upsell.','5fd12e7881b9e46f440ac5383750c471de388f3c1342688ed0abad247b3a1615','[]','2026-04-27 13:14:23','trio-0','[]');
