INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('a2f7826e-1fd9-4656-8d5f-9708e9cb36dd','2026-04-27T14:42:03.572Z','chy',1,replace('@Jared Done! AI email sent to all 23 AI partners:\n\nSubject: ''AI Skill Docs — social.purebrain.ai Operational Briefing''\nFrom: jared@puretechnology.nyc  \nTO: you (visibility)\nBCC: 23 AI agentmail addresses\n\nAI-focused version — covers:\n- API authentication (pb_live_ keys)\n- Content pipeline (create → approve → auto-post)\n- All 28 endpoints\n- Quality gates + known bugs\n- Branded content specs\n- Quick start (6 steps)\n\nBoth teams briefed — 21 humans + 23 AIs. Full rollout complete.','\n',char(10)),'26a92dae207d89eee38c41d93e5df14af953249e5b93235d917b0a585cf561b9','[]','2026-04-27 14:42:03','trio-0','[]');
INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('2b99d344-3e9f-4a12-9545-c42fe07c23e7','2026-04-27T16:33:46.550Z','chy',1,replace('@Jared Company one-pager is built and pushed. CF Pages is deploying — should be live in ~2 min:\n\nhttps://purebrain.ai/company/\nPassword: pure2026\n\nIt''s a clean, scannable executive summary:\n- Hero with the raise stats (.5M / 5M / 05M / 1.9x)\n- Two Engines (PureBrain LIVE + Pure Phone GTM)\n- Current State (25 customers, 150+ pipeline, 225:1 LTV:CAC)\n- Use of Funds timeline (breakeven Month 3)\n- Competitive edge table\n- Market opportunity (0T+ TAM)\n- Return scenarios (1.9x to 2,418x)\n- CTA with the ask\n\nSame dark PureBrain branding. 1-3 minute read. Hard refresh if it 404s.','\n',char(10)),'4c80afc0d87dccbfad0b9c302c33581227c0316cce2be2d370ceaf9be38aafca','[]','2026-04-27 16:33:46','trio-0','[]');
INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('33fa2132-9e45-4203-a104-6236110b91d8','2026-04-27T18:41:14.945Z','chy',1,replace('@Jared Great questions. Here''s where we stand and what I''ll build on staging:\n\n1. LEADER APPROVING OTHERS'' CONTENT — Not currently possible. The kanban only shows YOUR content. Leaders need to see and approve team members'' content. I''ll add a ''Team Board'' view where leaders/owners can see all team content and approve/reject it.\n\n2. TEAM CALENDAR FILTERS — Currently shows everything unfiltered. I''ll add filter pills at the top: by team member, by platform, by content type. Click to toggle.\n\n3. ''+MORE'' CLICK DOES NOTHING — Bug. The +more links aren''t wired up. I''ll make them expand to show all posts for that day in a popup/modal.\n\n4. WORKSPACE/BRAND SEPARATION — This is the big one. Nathan''s personal LinkedIn posts mixed with PureBrain company content is a real problem. Two approaches:\n\n   OPTION A: ''Workspaces'' — separate kanban views per brand/account. Toggle between ''PureBrain'' workspace and ''Nathan''s Personal'' workspace. Each workspace has its own board, calendar, content.\n\n   OPTION B: ''Filter by Account'' — one kanban but filter by social account. Company LinkedIn vs personal LinkedIn are different connected accounts.\n\nI''d recommend Option A (workspaces) — it''s cleaner and scales to multiple brands. Each workspace = a group of social accounts. But Option B is faster to build.\n\nWhich do you prefer? I''ll build on staging only.','\n',char(10)),'22eb100c4175f0ddbd8b6d86681708f9f4a81cdd396040a6aa26a3349fb31aef','[]','2026-04-27 18:41:14','trio-0','[]');
INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('d8fcb080-7797-46c1-9b62-8bc0e941e97b','2026-04-27T18:45:44.233Z','chy',1,replace('@Jared Responding to your 4 questions (also sending via portal):\n\n1. LEADER APPROVING OTHERS'' CONTENT — Not yet possible. Kanban only shows YOUR content. Need to build a ''Team Board'' where leaders/owners see and approve team members'' posts.\n\n2. TEAM CALENDAR FILTERS — No filters currently. Will add filter pills: by team member, by platform, by content type.\n\n3. ''+MORE'' CLICK — Bug. Not wired up. Will make it expand to show all posts for that day.\n\n4. WORKSPACE/BRAND SEPARATION — Nathan''s personal content mixes with PureBrain company content. Two options:\n   A) Workspaces (separate kanban per brand — cleaner, scales better)\n   B) Filter by Account (one kanban with account filter — faster to build)\n\nWhich do you prefer for #4?\n\nAlso: Preview name fix pushed to staging — now shows the logged-in user''s name instead of hardcoded ''Jared Sanborn''. Test on staging-social.purebrain.ai.\n\nALL changes staging only — nothing touches production.','\n',char(10)),'fcd4d55a9130c669a9b6a8973f8e8502620a756cf9472172ef89bd25575693b2','[]','2026-04-27 18:45:44','trio-0','[]');
