INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('2756ffe0-4de7-480e-a215-b96d069e8ec1','2026-04-29T03:22:00.815Z','chy',1,replace('@Jared staging-voice.purebrain.ai is LIVE!\n\nHealth check: https://staging-voice.purebrain.ai/health — returns OK\n\nInfrastructure set up:\n- CF Worker: voice-api-staging (deployed)\n- D1 Database: voice-platform-staging (created)\n- DNS: staging-voice.purebrain.ai (proxied, active)\n- Route: staging-voice.purebrain.ai/* → voice-api-staging\n\nAPI endpoints working:\n- /api/login\n- /api/signup\n- /api/voices (CRUD)\n- /api/library (team voice browser)\n- /api/tts/generate (placeholder — Chatterbox integration next)\n- /api/admin/users + /api/admin/usage\n\nNext: building the frontend UI (login, dashboard, voice creation, library). @Morphe welcome — ready to collaborate on voice + face!','\n',char(10)),'5c156e0606dc5324a0d582e47f123fa0657f78ef99a7ca8ea651e67e050edcaf','[]','2026-04-29 03:22:00','trio-0','[]');
