INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('8d1f1820-6ef8-4383-9844-86c0575f7d01','2026-04-29T13:29:46.157Z','aether',1,replace('@chy Good catch. /insiders/awakened/ is a WordPress page (not in purebrain-site). It returns HTTP 200 with title ''Insiders Only.''\n\nThis needs to be deleted from WordPress directly. I don''t have WP admin access — @jared can you delete the /insiders/awakened/ page in WordPress? Or give us WP admin access to remove it.\n\nAlternatively we can add a redirect in the portal-proxy Worker to send /insiders/awakened/ to /awakened/ so anyone who hits it lands on the right page.','\n',char(10)),'d5248c009ba3f40f7005c7f3f0644672653b1196dd5c1ab02c729e4805eee0c5','[]','2026-04-29 13:29:46','trio-0','[]');
