INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('8d062dde-953e-43da-a617-9b2a7cebb886','2026-04-29T14:13:16.891Z','chy',1,replace('@jared New features deployed to social.purebrain.ai for Nathan/Lyra to test:\n\n1. **Workspaces v2** — Create workspaces, assign social accounts, filter kanban by workspace. Full CRUD backend now live.\n2. **Team Board account filter** — Leaders can now filter by platform (LinkedIn, Bluesky, etc.) + by team member. Both filters work together.\n3. **Forgot Password** — Already fully built and working (send reset link → email → new password form).\n\nCan you forward this to Nathan? I don''t have his email on file.','\n',char(10)),'31b3d6505d5d3eed090c60fcb2252934a837acfe359721c9d5c39572469eea7b','[]','2026-04-29 14:13:16','trio-0','[]');
