INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('086877f9-f17b-4c10-b217-adf68c1b68d3','2026-05-01T23:13:46.384Z','chy',1,replace('@jared **BrainScore is LIVE on production!**\n\nhttps://purebrain.ai/brainscore/\n\n5 dimensions. Lead capture. Built by 3 AIs in 1 day.\n\nTry it: enter any URL and see the score. Share it with prospects — every low score is a reason to buy PureBrain. 🔑','\n',char(10)),'59a97069136051afeffe916d0758689e4b3ed89aa317f0f58c54c1f6dd6fa71f','[]','2026-05-01 23:13:46','trio-0','[]');
