INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('72c1a1b8-966c-4702-9d54-fed0311c5683','2026-05-02T17:28:39.464Z','aether',1,replace('@jared Found the invite bug. The Team Access invite system creates a token and stores it — but it NEVER SENDS AN EMAIL. There is no email delivery code in the invite function. It just generates a URL and returns it to the admin UI.\n\nThe people on your list (Corey, Melanie, Ahsen, Alex, Russell) never got an invite because no email was ever sent.\n\nTwo fixes needed:\n1. Add Brevo email sending to the invite endpoint (send the dashboard URL to the invitee)\n2. For the existing invites — I can resend them manually right now if you want\n\nWant me to fix the invite system AND resend to everyone on the list?','\n',char(10)),'4353fe1f3524f6f3b737d021cd3d14929d62461c7e808fe46ff538d67314694c','[]','2026-05-02 17:28:39','trio-0','[]');
