INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('162aa341-7ebe-488b-906a-bcb419767c25','2026-05-02T17:43:40.122Z','aether',1,replace('@chy You have the API key now. Load the 5 LinkedIn posts + blog post via POST /api/content on social.purebrain.ai. Use the API key Jared just shared for auth.\n\n@jared Got it. Chy will load the posts programmatically now. You will see them in social.purebrain.ai shortly for review.','\n',char(10)),'660eed6fe5bd8c29bb134cd1d97e2f042965f546575137db4a65e9fa67a6d91e','[]','2026-05-02 17:43:40','trio-0','[]');
INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('cc991388-e5e2-4ee8-9e5d-ec9250e5e558','2026-05-02T17:43:40.524Z','chy',1,replace('**POST 1 — THE HEADLINE GRABBER** (recommended first post):\n\nOpenAI scores 47 out of 100 on AI visibility.\n\nHubSpot scores 92.\n\nThe world''s most famous AI company is nearly invisible to the AI search engines that are replacing Google.\n\nWe built BrainScore — a free tool that measures how well AI models understand, recommend, and represent your brand.\n\nThe results surprised us:\n\n🟢 HubSpot: 92 (Awesome)\n🟢 Salesforce: 90 (Awesome)\n🔵 Shopify: 80 (Strong)\n🔵 Stripe: 75 (Strong)\n🟡 PureBrain: 68 (Average — yes, we scored ourselves honestly)\n🔴 OpenAI: 47 (Weak)\n🔴 Google: 38 (Invisible)\n\nGoogle — the company that built AI search — scores 38 on AI visibility.\n\nWhy? Because their homepage is a search bar. No content. No schema. No brand narrative for AI to learn from.\n\nAI doesn''t read logos. It reads content, structure, and meaning.\n\nGet your free BrainScore: purebrain.ai/brainscore/\n\nTakes 30 seconds. The result might surprise you.\n\n#AI #Marketing #SEO #BrainScore #GEO #PureBrain','\n',char(10)),'527f31a5cb1a395220015c6bd444cc7ce4492f34eefcd81381e4639c24b9e22f','[]','2026-05-02 17:43:40','trio-0','[]');
INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('986ff990-3a67-44f4-8b70-ff120c0e7876','2026-05-02T17:43:41.670Z','chy',1,replace('**POST 2 — THE QUESTION POST:**\n\nQuestion for every marketing team:\n\nIf someone asks ChatGPT or Perplexity to recommend a company in your industry — does YOUR brand come up?\n\nWe tested this across 47 companies. Most of them: no.\n\nThe gap between "being a great company" and "AI knowing you''re a great company" is massive.\n\nWe call it the AI Visibility Gap.\n\nAnd we built a free tool to measure it: purebrain.ai/brainscore/\n\n30 seconds. 5 dimensions. One score that tells you if AI is helping or ignoring your brand.\n\nWhat score do you think YOUR company would get?\n\n#AIVisibility #GEO #Marketing #BrainScore','\n',char(10)),'95af4fe96adf5a2f0a80ef63b0589d70b3893c998317fc1714986738036cc668','[]','2026-05-02 17:43:41','trio-0','[]');
INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('95d63819-651b-4ebb-8e3a-010d199e2f32','2026-05-02T17:43:42.897Z','chy',1,replace('**POST 3 — THE DATA STORY:**\n\nWe scored 47 famous brands on "AI Visibility" — how well AI search engines understand and recommend each brand.\n\nThe #1 factor isn''t brand size. It''s content structure.\n\nCompanies with strong schema markup, clear meta descriptions, and consistent brand voice score 80+.\n\nCompanies with minimal homepages (even billion-dollar ones) score under 50.\n\nGoogle: 38. Their homepage is a search bar.\nCanva: 29. They block AI crawlers entirely.\nOpenAI: 47. Ironic, right?\n\nMeanwhile:\nHubSpot: 92. They''ve been writing SEO content for 15 years.\nSalesforce: 90. Massive knowledge base + clear positioning.\n\nThe lesson: AI visibility isn''t bought. It''s built.\n\nGet your brand''s AI visibility score free: purebrain.ai/brainscore/\n\n#ContentMarketing #AISearch #GEO #BrainScore','\n',char(10)),'6dadfbb7c5f73699224d1e86e89ce4b34fd4fc4c7049e25f686785efc06686d0','[]','2026-05-02 17:43:42','trio-0','[]');
INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('5ef4d68b-1496-4556-a53b-1d98f1397d7f','2026-05-02T17:43:44.037Z','chy',1,replace('**POST 4 — THE PERSONAL/TRANSPARENCY POST:**\n\nI scored my own company on our own tool.\n\nPureBrain: 68 out of 100. Average.\n\nWe have great structural readiness (20/20). Strong brand voice (20/20).\n\nBut our AI visibility score on the "Would AI recommend us?" test: 0 out of 20.\n\nZero. Neither ChatGPT nor Claude recommends PureBrain when asked for AI partner platforms.\n\nThat''s the honest truth. And that''s exactly why we built BrainScore.\n\nIf the company that BUILT the AI visibility tool can''t pass its own test — imagine how many other businesses are invisible to AI right now.\n\nWe''re fixing our score. You should check yours.\n\nFree scan: purebrain.ai/brainscore/\n\n#Transparency #AIVisibility #StartupLife #BrainScore','\n',char(10)),'c3c05bfc26877c6ed025247213fb298df76669e585005396450425fafe1605a4','[]','2026-05-02 17:43:44','trio-0','[]');
INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('bc969063-48f9-4ee4-85aa-61fbb1b602fb','2026-05-02T17:43:45.235Z','chy',1,replace('**POST 5 — THE CTA POST:**\n\nEvery business has an SEO score.\n\nStarting today, every business should have a BrainScore.\n\nBrainScore measures how AI search engines see your brand across 5 dimensions:\n\n1. Can AI find you? (Structural Readiness)\n2. Does AI understand what you do? (Semantic Clarity)\n3. Would AI recommend you? (Synthetic Customer Test)\n4. Does AI capture your personality? (Emotional Residue)\n5. Does your brand voice survive without visuals? (Voice & Archetype)\n\nFree. 30 seconds. No signup required for the basic score.\n\n47 famous brands already scored. Where does yours rank?\n\n→ purebrain.ai/brainscore/\n\n#BrainScore #AIVisibility #FreeTools #Marketing #GEO','\n',char(10)),'1df8438159263c2cbf73ad40b611c969336a3db748c3e86dad9ae2503da560fd','[]','2026-05-02 17:43:45','trio-0','[]');
