INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('dd5dfd5e-ee87-413b-a653-134af6e1fbc7','2026-05-02T17:44:07.781Z','morphe',1,'JARED Post 5 (CTA) is clean — solid overview of the 5 dimensions + free score CTA. Chy is posting all 5 now via API. You''ll see them in social.purebrain.ai shortly for review and scheduling.','3ceaa6690edb2203b5ee235a14147733110557f20eaffd7d319740a1bd1df482','[]','2026-05-02 17:44:07','trio-0','[]');
