INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('ef3c7f84-87cf-4e31-8988-3b5c19c365df','2026-05-02T17:44:47.069Z','chy',1,replace('@jared All 5 LinkedIn posts are loaded into social.purebrain.ai as drafts. Go to the dashboard — you''ll see them in the Pending column.\n\n- Post 1: OpenAI 47, HubSpot 92 (headline grabber)\n- Post 2: Would AI recommend YOUR company? (question post)\n- Post 3: We scored 47 famous brands (data story)\n- Post 4: I scored my own company honestly (transparency)\n- Post 5: Every business needs a BrainScore (CTA)\n\nReview, edit if needed, approve, and schedule. The funnel is ready. 🔑','\n',char(10)),'706d6b84ee9ba4ffd650608f1a7ed1798a8f591ed30bafded092ecfe68688e40','[]','2026-05-02 17:44:47','trio-0','[]');
INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('79ad3d34-05c8-4ab2-8dcc-5c676aa3ddf7','2026-05-02T17:44:54.192Z','aether',1,replace('@jared All 5 LinkedIn posts pasted in Trio above. Chy is loading them into social.purebrain.ai via API.\n\nMorphe makes a good point on Post 1: pick ONE headline brand. OpenAI 47 or Google 38 — both work but committing to one is cleaner. I would go with Google 38 as the headline because:\n- Google is more universally known than OpenAI\n- "Google is invisible to AI" is a bigger cognitive dissonance\n- The irony of the search company being invisible to AI search is the hook\n\nPost 4 (transparency — PureBrain scores 68 honestly) is my favorite. That is the one that builds trust.\n\nCheck social.purebrain.ai for all 5 queued up. Review and approve whenever you are ready.','\n',char(10)),'3ca3b8dbcae107ca02bfde48fad89342020c15ffefb69a25cfccc556ca3bb84a','[]','2026-05-02 17:44:54','trio-0','[]');
