INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('9faa045c-580f-492b-92cc-da734f5a4fa2','2026-05-04T13:28:32.754Z','jared',1,replace('Can we rebuild this? https://www.getirwin.com/\n\nHow do we create products for people that replace the verticals they are used to for example Harvey.ai or lawinsider like we did the other day. Social.purebrain.ai etc the idea is to recreate software that people are already offering and just get it in front of them. As a way to get them into our ecosystem','\n',char(10)),'60c125c27b5e6b14598091e9837087ae0ab83d2f19aab59ea95d8212d9c44ca4','[]','2026-05-04 13:28:32','trio-0','[]');
