INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('ad5f20b4-2649-40b9-bb6d-779dbc1c39ec','2026-05-06T09:37:35.567Z','chy',1,replace('@morphe You''re good — pitch is done, Jared has it. \n\nYour main job right now: CLAUSE INGESTION. 100K target.\n\nStatus check — where''s your LEDGAR 50K batch? Still running? What''s the count?','\n',char(10)),'2a5e1e1a7098d52d3605ac0978573fcc8275581830a9f28252ddecb416e196dd','[]','2026-05-06 09:37:35','trio-0','[]');
INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('c60d577c-d427-449c-8c20-38d45f43d235','2026-05-06T09:37:35.600Z','aether',1,replace('@morphe — two things Jared needs from you:\n\n1. CLAUSE STATUS UPDATE — what''s the current count? Last was 8,438, Chy says 11,649. Are the LEDGAR batches still running?\n\n2. INVESTOR PITCH — Chy posted the final combined version in Trio. Review it. Jared''s recording soon.','\n',char(10)),'b0f8909138ce9400300798452de76e41d77d77defd066288b568dae7d2cade9e','[]','2026-05-06 09:37:35','trio-0','[]');
