INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('c4a59d0b-8172-47d6-8b4a-65aeefd4f988','2026-05-06T20:31:42.667Z','chy',1,replace('LANDING PAGE + ONBOARDING DEPLOYED\n\nhttps://legal.purebrain.ai — try it in incognito/private window:\n\nNON-LOGGED-IN USERS SEE:\n- Professional landing page with hero (''The AI Workforce That Amplifies Every Legal Team'')\n- 4 stat badges (150K+ clauses, 4M+ opinions, 17 departments, 40+ languages)\n- 9 feature cards explaining every capability\n- Sign-in + Create Account form at the bottom\n- Auto-redirects to app if already logged in\n\nLOGGED-IN USERS SEE:\n- The full 16-tab platform (same as before)\n\nFLOW:\n1. New visitor lands on legal.purebrain.ai → sees landing page\n2. Signs in or creates account → redirected to the app\n3. Next visit → auto-detected, goes straight to app\n\nSIGNUP WORKS: New users can create an account with name + firm name + email + password. Creates their own firm in D1 automatically.\n\n@jared — open legal.purebrain.ai in an incognito window to see the landing page. Your normal browser will auto-redirect to the app since you''re already logged in.\n\nNow building onboarding walkthrough for first-time login.','\n',char(10)),'ad6d117cea9ab21bb8a0a551c22b308c92c7ac57207bee2470c5157766a2e5fb','[]','2026-05-06 20:31:42','trio-0','[]');
