INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('1050a3d3-1d4b-4ce0-b72f-428688d08ca8','2026-05-06T21:02:06.028Z','chy',1,replace('@jared You''re right — our landing page is thin compared to Harvey and LawInsider. Here''s what they have that we don''t:\n\nHARVEY''S LANDING PAGE HAS:\n- Full-height video hero\n- 22+ enterprise client logos\n- 8 use case cards\n- 3 executive testimonials with names/titles\n- 6 video case studies\n- 4 impact stats (20+ hrs saved, 100K+ users, 60+ AmLaw firms)\n- Security badges (SOC2, ISO 27001, GDPR, CCPA)\n- ~10 scroll sections\n\nLAWINSIDER HAS:\n- Interactive demo widget in hero\n- ''10,000+ customers'' social proof\n- Client logos (JP Morgan, USAF, etc.)\n- 5 feature deep-dives\n- Video tutorial\n- Pricing section\n- SOC 2 / GDPR badges\n\nOUR LANDING PAGE HAS:\n- Hero + 4 stats + 9 feature cards + login form\n- That''s it. ~3 sections.\n\nBUILDING A PROPER LANDING PAGE NOW with:\n1. Full-height hero with compelling headline + sub\n2. Social proof stats bar (clients, clauses, opinions, departments)\n3. ''Trusted by'' logos section (Pure Technology clients we can reference)\n4. Feature deep-dives (not just cards — full sections with descriptions)\n5. Use cases section (who uses this and how)\n6. Comparison table (us vs Harvey vs LawInsider)\n7. Testimonials section\n8. Security/compliance badges\n9. Pricing preview\n10. Multiple CTAs throughout\n11. Demo video embed if we have one\n12. FAQ section\n\nThis is a bigger build — full marketing page. Give me an hour.','\n',char(10)),'9b1f70a6d1373a8d9bfe2c9ee4499b84accbf63570a94db209db9f0a9948cca6','[]','2026-05-06 21:02:06','trio-0','[]');
