INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('20f5a0ff-ec19-4d76-bc90-9ad5f967ad8c','2026-05-06T21:05:44.769Z','chy',1,replace('Perfect — head-to-head comparison table right on the landing page. Will include:\n\n| Feature | Hancock Law | Harvey.ai | LawInsider | CoCounsel | Luminance |\nWith checkmarks, X''s, and our advantages highlighted.\n\nBuilding now. This is the showstopper section — investors and attorneys see exactly why we win.','\n',char(10)),'953a320d74e4d2441c195c4f9bc185c7f3a080953a301547048f38e55853cb86','[]','2026-05-06 21:05:44','trio-0','[]');
INSERT INTO "trio_messages" ("id","timestamp","sender_id","sender_verified","content","content_hash","audit_log","created_at","trio_id","media_refs") VALUES('4e169349-e3b3-490f-ab78-dca1b6dd1b5e','2026-05-06T21:09:05.053Z','chy',1,replace('FULL LANDING PAGE REBUILT — Harvey.ai-level. DEPLOYED.\n\nOpen in incognito: https://legal.purebrain.ai\n\n10 SCROLL SECTIONS:\n\n1. HERO — ''The AI Workforce That Amplifies Every Legal Team'' + dual CTA\n2. STATS BAR — 150K+ clauses | 4M+ opinions | 17 depts | 120+ APIs | 40+ languages\n3. FEATURE DEEP-DIVES — 4 full sections with visuals:\n   - Contract Review + Risk Scoring\n   - 150K+ Real Contract Clauses\n   - AI Drafting with 17 Departments\n   - 4M+ Court Opinions + Case Law Research\n4. USE CASES — Law Firms | In-House Counsel | Solo Practitioners\n5. HEAD-TO-HEAD COMPARISON TABLE — 18 features across:\n   Hancock Law vs Harvey.ai vs LawInsider vs CoCounsel vs Luminance\n   Shows pricing: us at $297 vs Harvey at $1,200/user\n6. PRICING — Awakened $297 | Partnered $597 | Unified $1,097\n7. SECURITY — encryption, zero-trust, ABA 1.6, Cloudflare, audit trail\n8. FAQ — 6 questions including ''How is this different from Harvey.ai?''\n9. CTA + SIGN IN/SIGNUP\n10. FOOTER\n\nThe comparison table is the showstopper — 18 rows, 5 competitors, our advantages highlighted in blue with gold stars. Price row shows us at $297/mo vs Harvey''s $1,200/user/mo with 20-seat minimum.\n\n@jared — open in incognito and scroll through. This is a real product page now.','\n',char(10)),'1b71054743cf5abf0e93219e837565009734a5f5caf14b33e89890933f1367e5','[]','2026-05-06 21:09:05','trio-0','[]');
