PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE referrers (
    id            INTEGER PRIMARY KEY AUTOINCREMENT,
    user_name     TEXT NOT NULL DEFAULT '',
    user_email    TEXT NOT NULL UNIQUE COLLATE NOCASE,
    referral_code TEXT NOT NULL UNIQUE COLLATE NOCASE,
    paypal_email  TEXT NOT NULL DEFAULT '',
    password_hash TEXT NOT NULL DEFAULT '',
    created_at    TEXT NOT NULL
, partner_tier TEXT DEFAULT 'standard', total_sales INTEGER DEFAULT 0, split_config TEXT DEFAULT '[]', discount_enabled INTEGER DEFAULT 0, discount_percentage REAL DEFAULT 0.10, badge_earned INTEGER DEFAULT 0);
CREATE TABLE referrals (
    id             INTEGER PRIMARY KEY AUTOINCREMENT,
    referrer_id    INTEGER NOT NULL REFERENCES referrers(id),
    referred_email TEXT NOT NULL DEFAULT '' COLLATE NOCASE,
    referred_name  TEXT NOT NULL DEFAULT '',
    status         TEXT NOT NULL DEFAULT 'pending',
    created_at     TEXT NOT NULL,
    completed_at   TEXT
);
CREATE TABLE referral_clicks (
    id            INTEGER PRIMARY KEY AUTOINCREMENT,
    referral_code TEXT NOT NULL COLLATE NOCASE,
    ip_hash       TEXT NOT NULL DEFAULT '',
    clicked_at    TEXT NOT NULL
);
CREATE TABLE rewards (
    id          INTEGER PRIMARY KEY AUTOINCREMENT,
    referrer_id INTEGER NOT NULL REFERENCES referrers(id),
    referral_id INTEGER REFERENCES referrals(id),
    reward_type TEXT NOT NULL DEFAULT 'cash',
    reward_value REAL NOT NULL DEFAULT 0.0,
    issued_at   TEXT NOT NULL
);
CREATE TABLE commission_payments (
    id               INTEGER PRIMARY KEY AUTOINCREMENT,
    referrer_id      INTEGER NOT NULL REFERENCES referrers(id),
    referral_id      INTEGER NOT NULL REFERENCES referrals(id),
    payer_email      TEXT NOT NULL DEFAULT '' COLLATE NOCASE,
    order_id         TEXT NOT NULL DEFAULT '',
    payment_amount   REAL NOT NULL DEFAULT 0.0,
    commission_rate  REAL NOT NULL DEFAULT 0.05,
    commission_value REAL NOT NULL DEFAULT 0.0,
    tier             TEXT NOT NULL DEFAULT '',
    created_at       TEXT NOT NULL
);
CREATE TABLE admin_tokens (
    id         INTEGER PRIMARY KEY AUTOINCREMENT,
    token      TEXT NOT NULL UNIQUE,
    email      TEXT NOT NULL DEFAULT '',
    name       TEXT NOT NULL DEFAULT '',
    role       TEXT NOT NULL DEFAULT 'viewer',
    created_at TEXT NOT NULL
);
CREATE TABLE affiliate_sessions (
    id            INTEGER PRIMARY KEY AUTOINCREMENT,
    token         TEXT NOT NULL UNIQUE,
    referral_code TEXT NOT NULL COLLATE NOCASE,
    expires_at    INTEGER NOT NULL
);
CREATE TABLE rate_limits (
    key          TEXT PRIMARY KEY,
    count        INTEGER NOT NULL DEFAULT 0,
    window_start INTEGER NOT NULL DEFAULT 0
);
CREATE TABLE payout_requests (
    id            INTEGER PRIMARY KEY AUTOINCREMENT,
    request_id    TEXT NOT NULL UNIQUE,
    referral_code TEXT NOT NULL,
    paypal_email  TEXT NOT NULL DEFAULT '',
    amount        REAL NOT NULL DEFAULT 0.0,
    status        TEXT NOT NULL DEFAULT 'pending',
    created_at    TEXT NOT NULL,
    created_at_ts INTEGER NOT NULL DEFAULT 0,
    paid_at       TEXT,
    batch_id      TEXT DEFAULT '',
    notes         TEXT DEFAULT ''
);
CREATE TABLE trio_messages (id TEXT PRIMARY KEY, timestamp TEXT NOT NULL, sender_id TEXT NOT NULL, sender_verified INTEGER NOT NULL DEFAULT 0, content TEXT NOT NULL, content_hash TEXT NOT NULL, audit_log TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP, trio_id TEXT NOT NULL DEFAULT 'trio-0', media_refs TEXT DEFAULT '[]');
CREATE TABLE password_reset_tokens (id INTEGER PRIMARY KEY AUTOINCREMENT, referrer_id INTEGER, token TEXT NOT NULL UNIQUE, expires_at TEXT NOT NULL, created_at TEXT);
CREATE TABLE calculator_leads (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  email TEXT NOT NULL,
  first_name TEXT,
  score INTEGER,
  answers TEXT,
  utm_source TEXT,
  utm_medium TEXT,
  utm_campaign TEXT,
  created_at TEXT DEFAULT (datetime('now')),
  converted BOOLEAN DEFAULT 0
);
CREATE TABLE sessions (
       id INTEGER PRIMARY KEY AUTOINCREMENT,
       referrer_id INTEGER NOT NULL,
       token TEXT NOT NULL UNIQUE,
       created_at TEXT NOT NULL,
       expires_at TEXT NOT NULL
     );
CREATE TABLE login_attempts (
              id INTEGER PRIMARY KEY AUTOINCREMENT,
              identifier TEXT NOT NULL,
              attempted_at TEXT NOT NULL,
              success INTEGER DEFAULT 0
            );
CREATE TABLE commission_splits (
      id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))),
      referral_id TEXT NOT NULL,
      referrer_id TEXT NOT NULL,
      role TEXT NOT NULL,
      split_percentage REAL NOT NULL,
      commission_value REAL DEFAULT 0,
      status TEXT DEFAULT 'pending',
      created_at TEXT DEFAULT (datetime('now')),
      FOREIGN KEY (referral_id) REFERENCES referrals(id),
      FOREIGN KEY (referrer_id) REFERENCES referrers(id)
    );
DELETE FROM sqlite_sequence;
CREATE INDEX idx_referrals_referrer_id ON referrals(referrer_id);
CREATE INDEX idx_referrals_referred_email ON referrals(referred_email);
CREATE INDEX idx_referral_clicks_code ON referral_clicks(referral_code);
CREATE INDEX idx_rewards_referrer_id ON rewards(referrer_id);
CREATE INDEX idx_commission_referrer_id ON commission_payments(referrer_id);
CREATE INDEX idx_commission_order_id ON commission_payments(order_id);
CREATE INDEX idx_sessions_token ON affiliate_sessions(token);
CREATE INDEX idx_sessions_expires ON affiliate_sessions(expires_at);
CREATE INDEX idx_payout_requests_code ON payout_requests(referral_code);
CREATE INDEX idx_trio_timestamp ON trio_messages(timestamp);
CREATE INDEX idx_trio_sender ON trio_messages(sender_id);
CREATE INDEX idx_trio_messages_trio_id ON trio_messages(trio_id);
CREATE INDEX idx_calculator_leads_email ON calculator_leads(email);
CREATE INDEX idx_calculator_leads_created ON calculator_leads(created_at);
